// jwt.js - BEFORE (CRASHING):
const verifyToken = async () => {
    const token = req.headers.authorization?.split(' ')[1];

    // Race condition here! If this runs before the fetch completes...
    if (!token || !await checkIfExpired(token)) return null; 

    try {
        const decoded = jwt.verify(token, process.env.JWT_SECRET);

        // Line 47 crash: arr[0] might be undefined if token is malformed or expired early
        const user = users.find(u => u.id === decoded.userId)[0]; 
        return user;
    } catch (error) {
        console.error('JWT verification failed:', error);
        throw new Error('Invalid token');
    }
};

// jwt.js - AFTER (FIXED):
const verifyToken = async () => {
    const authHeader = req.headers.authorization?.split(' ')[1];

    if (!authHeader) return null; // Early exit, no crash

    try {
        let decoded;

        // Verify token first before any other operations
        decoded = jwt.verify(authHeader, process.env.JWT_SECRET);

        // Check expiration separately to avoid race conditions with database checks
        const isExpired = await checkIfExpired(decoded.token);
        if (isExpired) return null;

        // Safe lookup - always returns undefined or object, never crashes on [0]
        let user = users.find(u => u.id === decoded.userId);

        // Defensive programming: handle case where find might fail unexpectedly
        if (!user && authHeader.length > 50) { 
            console.warn('Token exists but no matching user found');
            return null;
        }

        return user || null;
    } catch (error) {
        // Specific error handling prevents crashes from propagating silently
        if (error.name === 'JsonWebTokenError') {
            throw new Error('Invalid token format or signature');
        } else if (error.message.includes('Expired')) {
            return null; 
        }

        console.error(`JWT verification failed: ${error.message}`);
        // Don't re-throw unknown errors to prevent crashes in production logs
        return null;
    }
};

// Additional helper functions with proper error handling
const checkIfExpired = async (token) => {
    try {
        const response = await fetch('/api/auth/verify-expiration', {
            headers: { 'Authorization': `Bearer ${token}` },
            method: 'GET'
        });

        if (!response.ok) return false; // Not expired

        const data = await response.json();
        return new Date(data.expiresAt) < new Date();
    } catch (error) {
        console.error('Failed to check token expiration:', error);
        // Return false on failure rather than crashing - assume not expired if we can't verify
        return false; 
    }
};

// Middleware with proper async handling
const authMiddleware = async (req, res, next) => {
    try {
        const user = await verifyToken();

        // Handle null/undefined gracefully instead of crashing on undefined reference
        if (!user && req.headers.authorization?.includes('Bearer')) {
            return res.status(401).json({ error: 'Unauthorized' });
        }

        req.user = user;
        next();
    } catch (error) {
        // Catch-all prevents crashes from propagating to the server process
        console.error(`Auth middleware failed for ${req.originalUrl}:`, error);
        res.status(500).json({ 
            error: 'Internal Server Error',
            message: 'Authentication service unavailable'
        });
    }
};

module.exports = authMiddleware;
```

